INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('medical-tech-moex-15488', 'medical-tech', 'medical-tech-moex-099-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '下列關於在檢體中分離出病毒的敘述，何者錯誤？', '["在眼內分離出腺病毒（adenoviruses）或腸病毒70型（enterovirus type 70），是與疾病有密切相關的", "在呼吸道內分離出巨細胞病毒（cytomegalovirus），是與疾病有密切相關的", "在呼吸道內分離出流感病毒（influenza viruses）或呼吸道融合病毒（respiratory syncytial virus）， 是與疾病有密切相關的", "在尿內分離出腮腺炎病毒（mumps），是與疾病有密切相關的"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:02+00:00", "source_pdf_sha1": "875548fcaa4f", "answer_pdf_sha1": "c697768d0426", "source_family": "moex-gov-tw", "moex": {"exam_code": "099130", "c": "104", "s": "600", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "099", "exam_name": "099年第二次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、法醫師、聽力師", "original_question_number": 70, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-15489', 'medical-tech', 'medical-tech-moex-099-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '下列有關呼吸道融合病毒（respiratory syncytial virus）之檢驗的敘述，何者錯誤？', '["較好的方法是直接測檢體中的病毒抗原、核酸、或病毒培養，非測抗體", "病毒培養用的檢體，用nasopharyngeal swabs or nasal washes", "呼吸道融合病毒不穩定，應立即完成接種", "健康人也常可分離出呼吸道融合病毒"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:02+00:00", "source_pdf_sha1": "875548fcaa4f", "answer_pdf_sha1": "c697768d0426", "source_family": "moex-gov-tw", "moex": {"exam_code": "099130", "c": "104", "s": "600", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "099", "exam_name": "099年第二次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、法醫師、聽力師", "original_question_number": 71, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-15490', 'medical-tech', 'medical-tech-moex-099-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '關於細胞培養，下列敘述何者錯誤？', '["Trypan blue常被用於活細胞計數染色之用", "Dimethyl sulfoxide為細胞之冰凍保存劑", "要慢速冷凍及解凍細胞", "黴漿菌（Mycoplasma）常污染細胞培養，而不易察覺"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:02+00:00", "source_pdf_sha1": "875548fcaa4f", "answer_pdf_sha1": "c697768d0426", "source_family": "moex-gov-tw", "moex": {"exam_code": "099130", "c": "104", "s": "600", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "099", "exam_name": "099年第二次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、法醫師、聽力師", "original_question_number": 72, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-15491', 'medical-tech', 'medical-tech-moex-099-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '下列何者並非病毒學上一般使用之細胞培養條件？', '["37°C", "5% CO 2", "5~15% fetal bovine serum", "lactose為能量來源"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:02+00:00", "source_pdf_sha1": "875548fcaa4f", "answer_pdf_sha1": "c697768d0426", "source_family": "moex-gov-tw", "moex": {"exam_code": "099130", "c": "104", "s": "600", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "099", "exam_name": "099年第二次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、法醫師、聽力師", "original_question_number": 73, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-15492', 'medical-tech', 'medical-tech-moex-099-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '關於human immunodeficiency virus（HIV）病毒的檢驗，下列敘述何者錯誤？', '["欲做病毒培養時，較為敏感的方法，是將檢體與未被感染、且用mitogen刺激的peripheral blood mononuclear cells，共同培養", "以西方墨點（Western blot）法篩選愛滋病毒的抗體", "以RT-PCR或bDNA法測愛滋病毒的RNA", "感染初期，低量的HIV p24抗原，可用酶連免疫吸附試驗（enzyme-linked immunosorbent assay; ELISA）偵測到"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:02+00:00", "source_pdf_sha1": "875548fcaa4f", "answer_pdf_sha1": "c697768d0426", "source_family": "moex-gov-tw", "moex": {"exam_code": "099130", "c": "104", "s": "600", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "099", "exam_name": "099年第二次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、法醫師、聽力師", "original_question_number": 74, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-15493', 'medical-tech', 'medical-tech-moex-099-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '有關A型流行性感冒病毒（influenza A virus）之病毒檢驗，下列敘述何者錯誤？', '["檢體（nasal washings and/or throat swabs）需於症狀出現3天內取得", "檢體保存於4°C，並儘速接種；如需超過3天，須保存於-70°C", "培養病毒時，需要有5%胎牛血清", "培養出的病毒，以血液凝集抑制試驗（hemagglutination inhibition assay）來分亞型"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:02+00:00", "source_pdf_sha1": "875548fcaa4f", "answer_pdf_sha1": "c697768d0426", "source_family": "moex-gov-tw", "moex": {"exam_code": "099130", "c": "104", "s": "600", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "099", "exam_name": "099年第二次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、法醫師、聽力師", "original_question_number": 75, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-15494', 'medical-tech', 'medical-tech-moex-099-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '使用於治療A型流行性感冒病毒之抗病毒藥物（amantadine）其作用機制為抑制病毒的：', '["hemagglutinin與細胞之結合", "M2離子通道之作用", "neuraminidase之作用", "RNA polymerase之作用"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:02+00:00", "source_pdf_sha1": "875548fcaa4f", "answer_pdf_sha1": "c697768d0426", "source_family": "moex-gov-tw", "moex": {"exam_code": "099130", "c": "104", "s": "600", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "099", "exam_name": "099年第二次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、法醫師、聽力師", "original_question_number": 76, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-15495', 'medical-tech', 'medical-tech-moex-099-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '可用干擾素治療的病毒有那兩種？', '["HAV及HEV", "HBV及HCV", "HAV及HCV", "HAV及HBV"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:02+00:00", "source_pdf_sha1": "875548fcaa4f", "answer_pdf_sha1": "c697768d0426", "source_family": "moex-gov-tw", "moex": {"exam_code": "099130", "c": "104", "s": "600", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "099", "exam_name": "099年第二次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、法醫師、聽力師", "original_question_number": 77, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-15496', 'medical-tech', 'medical-tech-moex-099-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '下列關於病毒性質的敘述，何者錯誤？', '["一般病毒在pH 5至pH 9之間，是穩定的", "一般而言具有外套膜的病毒對chloroform是敏感的", "小RNA病毒（包括腸病毒與鼻病毒）均可耐酸", "耐酸試驗是以pH 3處理病毒1小時，來測量病毒活性"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:02+00:00", "source_pdf_sha1": "875548fcaa4f", "answer_pdf_sha1": "c697768d0426", "source_family": "moex-gov-tw", "moex": {"exam_code": "099130", "c": "104", "s": "600", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "099", "exam_name": "099年第二次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、法醫師、聽力師", "original_question_number": 78, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-15497', 'medical-tech', 'medical-tech-moex-099-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '進行病毒特異性感染的檢驗，應使用下列何種方法？', '["病毒干擾試驗", "血球吸附試驗", "細胞病變觀察", "免疫螢光染色"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:02+00:00", "source_pdf_sha1": "875548fcaa4f", "answer_pdf_sha1": "c697768d0426", "source_family": "moex-gov-tw", "moex": {"exam_code": "099130", "c": "104", "s": "600", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "099", "exam_name": "099年第二次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、法醫師、聽力師", "original_question_number": 79, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL)
